import { useEffect, useState } from "react";
import { auth, db } from "./firebase";
import { onAuthStateChanged } from "firebase/auth";
import { doc, getDoc } from "firebase/firestore";

import Login from "./pages/Login";
import Register from "./pages/Register";
import CustomerDashboard from "./pages/CustomerDashboard";
import AgentDashboard from "./pages/AgentDashboard";

function App() {
  const [user, setUser] = useState(null);
  const [role, setRole] = useState(null);
  const [register, setRegister] = useState(false);

  useEffect(() => {
    onAuthStateChanged(auth, async (u) => {
      if (u) {
        setUser(u);

        const agentDoc = await getDoc(doc(db, "agents", u.uid));
        setRole(agentDoc.exists() ? "agent" : "customer");
      } else {
        setUser(null);
        setRole(null);
      }
    });
  }, []);

  if (!user) {
    return register
      ? <Register setUser={setUser} goLogin={() => setRegister(false)} />
      : <Login setUser={setUser} goRegister={() => setRegister(true)} />;
  }

  return role === "agent"
    ? <AgentDashboard user={user} />
    : <CustomerDashboard user={user} />;
}

export default App;
